const items = $input.all();
const startTime = $('Extract & Validate Call Metadata').first().json.start_time || Date.now();
const callerId = $('Extract & Validate Call Metadata').first().json.caller_id || '';

let pipedriveData = null;
try {
  const pipedriveNode = $('Pipedrive: Lookup Person').all();
  if (pipedriveNode.length > 0 && pipedriveNode[0].json.data && pipedriveNode[0].json.data.items && pipedriveNode[0].json.data.items.length > 0) {
    const person = pipedriveNode[0].json.data.items[0].item;
    pipedriveData = {
      id: person.id,
      name: person.name,
      first_name: person.first_name || (person.name ? person.name.split(' ')[0] : ''),
      org_name: (person.organization && person.organization.name) ? person.organization.name : '',
      org_id: (person.organization && person.organization.id) ? person.organization.id : 0,
      account_tier: (person.custom_fields && person.custom_fields.account_tier) ? person.custom_fields.account_tier : null,
      industry: (person.custom_fields && person.custom_fields.industry) ? person.custom_fields.industry : ''
    };
  }
} catch (e) { /* Pipedrive lookup failed */ }

let callHistoryData = null;
try {
  const dtNode = $('Data Table: Lookup Call History').all();
  if (dtNode.length > 0 && dtNode[0].json) {
    const row = dtNode[0].json;
    callHistoryData = {
      name: row.name || '',
      call_count: parseInt(row.call_count) || 0,
      last_interaction: row.last_interaction || '',
      last_topic: row.last_topic || '',
      notes: row.notes || ''
    };
  }
} catch (e) { /* Data Table lookup failed */ }

function sanitize(text) {
  if (!text) return '';
  text = text.replace(/\d{3}-\d{2}-\d{4}/g, '[REDACTED]');
  text = text.replace(/\d{16}/g, '[REDACTED]');
  if (text.length > 200) text = text.substring(0, 197) + '...';
  return text;
}

function calculateTier(callCount) {
  if (callCount === 0) return 'New';
  if (callCount <= 5) return 'Bronze';
  if (callCount <= 15) return 'Silver';
  return 'Gold';
}

var customerName = (pipedriveData && pipedriveData.name) ? pipedriveData.name : ((callHistoryData && callHistoryData.name) ? callHistoryData.name : 'there');
var customerFirstName = (pipedriveData && pipedriveData.first_name) ? pipedriveData.first_name : ((callHistoryData && callHistoryData.name) ? callHistoryData.name.split(' ')[0] : 'there');
var company = (pipedriveData && pipedriveData.org_name) ? pipedriveData.org_name : '';
var industry = (pipedriveData && pipedriveData.industry) ? pipedriveData.industry : '';
var interactionCount = (callHistoryData && callHistoryData.call_count) ? callHistoryData.call_count : 0;
var accountTier = (pipedriveData && pipedriveData.account_tier) ? pipedriveData.account_tier : calculateTier(interactionCount);
var callHistory = (callHistoryData && callHistoryData.last_interaction) ? callHistoryData.last_interaction : 'First-time caller';
var lastTopic = (callHistoryData && callHistoryData.last_topic) ? callHistoryData.last_topic : '';
var notes = sanitize((callHistoryData && callHistoryData.notes) ? callHistoryData.notes : '');

var lookupSuccess = !!(pipedriveData || callHistoryData);
var dataSource = pipedriveData ? 'pipedrive' : (callHistoryData ? 'data_table' : 'none');

var dynamicVariables = {
  customer_name: customerName,
  customer_first_name: customerFirstName,
  company: company,
  industry: industry,
  account_tier: accountTier,
  call_history: callHistory,
  interaction_count: interactionCount,
  last_topic: lastTopic,
  notes: notes,
  lookup_success: lookupSuccess,
  data_source: dataSource,
  secret__pipedrive_person_id: (pipedriveData && pipedriveData.id) ? pipedriveData.id : 0,
  secret__pipedrive_org_id: (pipedriveData && pipedriveData.org_id) ? pipedriveData.org_id : 0
};

var response = {
  type: 'conversation_initiation_client_data',
  dynamic_variables: dynamicVariables
};

if (accountTier === 'Gold') {
  response.conversation_config_override = {
    agent: { first_message: 'Hi ' + customerFirstName + ', this is client from example. I see you are one of our premium clients - how can I help you today?' }
  };
} else if (interactionCount >= 3) {
  response.conversation_config_override = {
    agent: { first_message: 'Hi ' + customerFirstName + ', great to hear from you again! This is client from example.' }
  };
}

var executionTime = Date.now() - startTime;
var metadata = {
  caller_id: callerId,
  execution_time_ms: executionTime,
  pipedrive_success: !!pipedriveData,
  data_table_success: !!callHistoryData,
  enrichment_success: lookupSuccess,
  account_tier: accountTier,
  data_source: dataSource
};

return [{ json: { response: response, metadata: metadata } }];

var response = {
  type: 'conversation_initiation_client_data',
  dynamic_variables: {
    customer_name: 'there',
    customer_first_name: 'there',
    company: '',
    industry: '',
    account_tier: 'New',
    call_history: 'First-time caller',
    interaction_count: 0,
    last_topic: '',
    notes: '',
    lookup_success: false,
    data_source: 'none',
    secret__pipedrive_person_id: 0,
    secret__pipedrive_org_id: 0
  }
};
return [{ json: { response: response } }];
